import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function AdminProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    fetchUser();
  }, []);

  const fetchUser = () => {
    try {
      const stored = JSON.parse(localStorage.getItem("user"));

      if (!stored?.email) {
        navigate("/");
        return;
      }

      axios
        .get("http://localhost:8086/user/profile", {
          params: { email: stored.email },
        })
        .then((res) => {
          setUser(res.data);
        })
        .catch((err) => {
          console.log("Profile fetch error:", err);
        });

    } catch (e) {
      console.log("LocalStorage error:", e);
      navigate("/");
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div>Loading profile...</div>
      </div>
    );
  }

  const isAdminOrAcademic =
    user.role?.toLowerCase() === "admin" ||
    user.role?.toLowerCase().includes("academic");

  return (
    <div className="min-h-screen bg-gray-100 p-8 ml-[17vw]">

      <h1 className="text-2xl font-bold mb-6">{user.role} Profile</h1>

      <div className="grid grid-cols-3 gap-6">

        {/* LEFT */}
        <div className="bg-white p-6 rounded-xl shadow text-center">

          <img
            src={
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            className="w-24 h-24 rounded-full mx-auto"
          />

          <h2 className="mt-3 font-bold">{user.name}</h2>
          <p className="text-sm text-gray-500">{user.email}</p>

          {isAdminOrAcademic && (
            <button
              onClick={() => setShowEditProfile(true)}
              className="mt-4 w-full bg-indigo-600 text-white py-2 rounded"
            >
              Edit Profile
            </button>
          )}

          <button
            onClick={() => {
              localStorage.clear();
              navigate("/");
              window.location.reload();
            }}
            className="mt-2 w-full bg-red-500 text-white py-2 rounded"
          >
            Logout
          </button>

        </div>

        {/* RIGHT */}
        <div className="col-span-2 bg-white p-6 rounded-xl shadow">
          <p><b>Username:</b> {user.username}</p>
          <p><b>Role:</b> {user.role}</p>
        </div>

      </div>

      {/* 🔥 MODAL LINK (IMPORTANT FIX) */}
      {showEditProfile && (
        <EditProfile
          closeModal={() => setShowEditProfile(false)}
          onUpdate={fetchUser}   // 🔥 THIS FIXES YOUR ISSUE
        />
      )}

    </div>
  );
}
